1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
12	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
13	int qled_shadow;
14	
15	// Apply a binary op to two scalars
16	int eval_binop_scalar(int op, int a, int b) {
17	    if (op == TOK_PLUS)       return a + b;
18	    if (op == TOK_MINUS)      return a - b;
19	    if (op == TOK_STAR)       return a * b;
20	    if (op == TOK_SLASH) {
21	        if (b == 0) { eval_err = 1; return 0; }
22	        return a / b;
23	    }
24	    eval_err = 1;
25	    return 0;
26	}
27	
28	// Evaluate AST node, return heap index of result array.
29	// On error, sets eval_err and returns -1.
30	int eval(int n) {
31	    if (eval_err) return -1;
32	    if (n < 0 || n >= node_count) {
33	        eval_err = 1;
34	        return -1;
35	    }
36	
37	    int ty = node_type[n];
38	
39	    if (ty == NODE_NUM) {
40	        int r = arr_scalar(node_val[n]);
41	        if (r < 0) { eval_err = 5; return -1; }
42	        return r;
43	    }
44	
45	    if (ty == NODE_VEC) {
46	        return node_val[n];
47	    }
48	
49	    if (ty == NODE_IDENT) {
50	        int idx = node_val[n];
51	        if (!sym_set_flag[idx]) {
52	            eval_err = 2;
53	            return -1;
54	        }
55	        return sym_val[idx];
56	    }
57	
58	    if (ty == NODE_ASSIGN) {
59	        int idx = node_val[n];
60	        int v = eval(node_right[n]);
61	        if (eval_err) return -1;
62	        sym_val[idx] = v;
63	        sym_set_flag[idx] = 1;
64	        return v;
65	    }
66	
67	    if (ty == NODE_QOUT) {
68	        int v = eval(node_right[n]);
69	        if (eval_err) return -1;
70	        return v;
71	    }
72	
73	    if (ty == NODE_QLED) {
74	        // Read LED D2 from shadow register (1=on, 0=off)
75	        int r = arr_scalar(qled_shadow);
76	        if (r < 0) { eval_err = 5; return -1; }
77	        return r;
78	    }
79	
80	    if (ty == NODE_QSW) {
81	        // Read switch S2: bit 0 of 0xFF0000, inverted (1=pressed, 0=released)
82	        int raw = *(char *)0xFF0000;
83	        int val = (raw ^ 1) & 1;
84	        int r = arr_scalar(val);
85	        if (r < 0) { eval_err = 5; return -1; }
86	        return r;
87	    }
88	
89	    if (ty == NODE_QLED_ASSIGN) {
90	        int v = eval(node_right[n]);
91	        if (eval_err) return -1;
92	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
93	        int val = arr_get(v, 0) & 1;
94	        qled_shadow = val;
95	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
96	        *(char *)0xFF0000 = val ^ 1;
97	        return v;
98	    }
99	
100	    if (ty == NODE_QSVO) {
101	        // Shared variable offer: IDENT qsvo AP
102	        // Evaluate AP number, couple symbol if AP supported
103	        int v = eval(node_right[n]);
104	        if (eval_err) return -1;
105	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
106	        int ap = arr_get(v, 0);
107	        int sym_idx = node_val[n];
108	        if (ap == 242) {
109	            // AP 242: MMIO byte access (FF0000+offset)
110	            svo_ap[sym_idx] = 242;
111	            int r = arr_scalar(2);
112	            if (r < 0) { eval_err = 5; return -1; }
113	            return r;
114	        }
115	        // Unknown AP: return 0 (not coupled)
116	        svo_ap[sym_idx] = 0;
117	        int r = arr_scalar(0);
118	        if (r < 0) { eval_err = 5; return -1; }
119	        return r;
120	    }
121	
122	    if (ty == NODE_SVO_READ) {
123	        // Indexed read: IDENT[N]
124	        int sym_idx = node_val[n];
125	        int ap = svo_ap[sym_idx];
126	        if (ap != 0) {
127	            // Shared variable MMIO access
128	            int v = eval(node_right[n]);
129	            if (eval_err) return -1;
130	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
131	            int offset = arr_get(v, 0);
132	            if (ap == 242) {
133	                int addr = 0xFF0000 + offset;
134	                int val = *(char *)addr;
135	                val = val & 0xFF;
136	                int r = arr_scalar(val);
137	                if (r < 0) { eval_err = 5; return -1; }
138	                return r;
139	            }
140	            eval_err = 1;
141	            return -1;
142	        }
143	        // Regular vector bracket indexing: V[N]
144	        if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
145	        int arr = sym_val[sym_idx];
146	        int v = eval(node_right[n]);
147	        if (eval_err) return -1;
148	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
149	        int idx = arr_get(v, 0);
150	        int sz = arr_size(arr);
151	        if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // INDEX ERROR
152	        int val = arr_get(arr, idx);
153	        int r = arr_scalar(val);
154	        if (r < 0) { eval_err = 5; return -1; }
155	        return r;
156	    }
157	
158	    if (ty == NODE_SVO_WRITE) {
159	        // Indexed write: IDENT[N] <- expr
160	        int sym_idx = node_val[n];
161	        int ap = svo_ap[sym_idx];
162	        if (ap != 0) {
163	            // Shared variable MMIO write
164	            int idx = eval(node_left[n]);
165	            if (eval_err) return -1;
166	            if (arr_rank(idx) != 0) { eval_err = 4; return -1; }
167	            int offset = arr_get(idx, 0);
168	            int v = eval(node_right[n]);
169	            if (eval_err) return -1;
170	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
171	            int val = arr_get(v, 0);
172	            if (ap == 242) {
173	                int addr = 0xFF0000 + offset;
174	                *(char *)addr = val & 0xFF;
175	                return v;
176	            }
177	            eval_err = 1;
178	            return -1;
179	        }
180	        // Regular vector bracket indexed write: V[N] <- expr
181	        if (!sym_set_flag[sym_idx]) { eval_err = 2; return -1; }
182	        int arr = sym_val[sym_idx];
183	        int idxv = eval(node_left[n]);
184	        if (eval_err) return -1;
185	        if (arr_rank(idxv) != 0) { eval_err = 4; return -1; }
186	        int idx = arr_get(idxv, 0);
187	        int v = eval(node_right[n]);
188	        if (eval_err) return -1;
189	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
190	        int val = arr_get(v, 0);
191	        int sz = arr_size(arr);
192	        if (idx < 0 || idx >= sz) { eval_err = 3; return -1; }  // INDEX ERROR
193	        arr_set(arr, idx, val);
194	        return v;
195	    }
196	
197	    if (ty == NODE_NEG) {
198	        int v = eval(node_right[n]);
199	        if (eval_err) return -1;
200	        int rk = arr_rank(v);
201	        if (rk == 0) {
202	            int r = arr_scalar(0 - arr_get(v, 0));
203	            if (r < 0) { eval_err = 5; return -1; }
204	            return r;
205	        }
206	        // Negate each element of vector
207	        if (rk == 1) {
208	            int sz = arr_size(v);
209	            int r = arr_vector(sz);
210	            if (r < 0) { eval_err = 5; return -1; }
211	            int i = 0;
212	            while (i < sz) {
213	                arr_set(r, i, 0 - arr_get(v, i));
214	                i++;
215	            }
216	            return r;
217	        }
218	        // Negate each element of matrix
219	        if (rk == 2) {
220	            int d0 = arr_dim0(v);
221	            int d1 = arr_dim1(v);
222	            int sz = d0 * d1;
223	            int r = arr_new(2, d0, d1);
224	            if (r < 0) { eval_err = 5; return -1; }
225	            int i = 0;
226	            while (i < sz) {
227	                arr_set(r, i, 0 - arr_get(v, i));
228	                i++;
229	            }
230	            return r;
231	        }
232	        eval_err = 4;
233	        return -1;
234	    }
235	
236	    if (ty == NODE_MONAD) {
237	        int v = eval(node_right[n]);
238	        if (eval_err) return -1;
239	        int res_id = node_val[n];
240	
241	        if (res_id == RES_IOTA) {
242	            // iota N: generate vector 0 1 2 ... N-1
243	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
244	            int count = arr_get(v, 0);
245	            if (count < 0) { eval_err = 1; return -1; }
246	            int r = arr_vector(count);
247	            if (r < 0) { eval_err = 5; return -1; }
248	            int i = 0;
249	            while (i < count) {
250	                arr_set(r, i, i);
251	                i++;
252	            }
253	            return r;
254	        }
255	
256	        if (res_id == RES_RHO) {
257	            // rho A: return shape of A
258	            int rk = arr_rank(v);
259	            if (rk == 0) {
260	                // Scalar: shape is empty vector
261	                int r = arr_vector(0);
262	                if (r < 0) { eval_err = 5; return -1; }
263	                return r;
264	            }
265	            if (rk == 1) {
266	                // Vector: shape is 1-element vector with length
267	                int r = arr_scalar(arr_dim0(v));
268	                if (r < 0) { eval_err = 5; return -1; }
269	                return r;
270	            }
271	            if (rk == 2) {
272	                // Matrix: shape is 2-element vector (rows cols)
273	                int r = arr_vector(2);
274	                if (r < 0) { eval_err = 5; return -1; }
275	                arr_set(r, 0, arr_dim0(v));
276	                arr_set(r, 1, arr_dim1(v));
277	                return r;
278	            }
279	            eval_err = 4;
280	            return -1;
281	        }
282	
283	        if (res_id == RES_REV) {
284	            // rev A: reverse a vector
285	            int rk = arr_rank(v);
286	            if (rk == 0) {
287	                // Scalar: reverse is identity
288	                return v;
289	            }
290	            if (rk == 1) {
291	                int sz = arr_size(v);
292	                int r = arr_vector(sz);
293	                if (r < 0) { eval_err = 5; return -1; }
294	                int i = 0;
295	                while (i < sz) {
296	                    arr_set(r, i, arr_get(v, sz - 1 - i));
297	                    i++;
298	                }
299	                return r;
300	            }
301	            eval_err = 4;
302	            return -1;
303	        }
304	
305	        if (res_id == RES_CAT) {
306	            // Monadic cat: ravel (flatten to 1D vector)
307	            int rk = arr_rank(v);
308	            if (rk == 0) {
309	                // Scalar -> 1-element vector
310	                int r = arr_vector(1);
311	                if (r < 0) { eval_err = 5; return -1; }
312	                arr_set(r, 0, arr_get(v, 0));
313	                return r;
314	            }
315	            if (rk == 1) {
316	                // Vector: already 1D, return as-is
317	                return v;
318	            }
319	            if (rk == 2) {
320	                // Matrix -> vector of all elements
321	                int sz = arr_size(v);
322	                int r = arr_vector(sz);
323	                if (r < 0) { eval_err = 5; return -1; }
324	                int i = 0;
325	                while (i < sz) {
326	                    arr_set(r, i, arr_get(v, i));
327	                    i++;
328	                }
329	                return r;
330	            }
331	            eval_err = 4;
332	            return -1;
333	        }
334	
335	        // Unknown monadic function
336	        eval_err = 1;
337	        return -1;
338	    }
339	
340	    if (ty == NODE_REDUCE) {
341	        int v = eval(node_right[n]);
342	        if (eval_err) return -1;
343	        int op = node_val[n];
344	        int rk = arr_rank(v);
345	
346	        // Scalar reduce: just return the scalar
347	        if (rk == 0) {
348	            return v;
349	        }
350	
351	        // Vector reduce: right-to-left fold
352	        if (rk == 1) {
353	            int sz = arr_size(v);
354	            if (sz == 0) {
355	                // Empty vector: return identity element
356	                int id;
357	                if (op == TOK_PLUS || op == TOK_MINUS) id = 0;
358	                else if (op == TOK_STAR || op == TOK_SLASH) id = 1;
359	                else { eval_err = 1; return -1; }
360	                int r = arr_scalar(id);
361	                if (r < 0) { eval_err = 5; return -1; }
362	                return r;
363	            }
364	            int acc = arr_get(v, sz - 1);
365	            int i = sz - 2;
366	            while (i >= 0) {
367	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
368	                if (eval_err) return -1;
369	                i--;
370	            }
371	            int r = arr_scalar(acc);
372	            if (r < 0) { eval_err = 5; return -1; }
373	            return r;
374	        }
375	
376	        // Unsupported rank for reduce
377	        eval_err = 4;
378	        return -1;
379	    }
380	
381	    if (ty == NODE_DYAD) {
382	        int lv = eval(node_left[n]);
383	        if (eval_err) return -1;
384	        int rv = eval(node_right[n]);
385	        if (eval_err) return -1;
386	        int res_id = node_val[n];
387	
388	        if (res_id == RES_RHO) {
389	            // S rho A: reshape A to shape S with cyclic fill
390	            // S is scalar -> result is vector of that length
391	            // S is 2-element vector -> result is matrix
392	            int lrk = arr_rank(lv);
393	            int new_rank;
394	            int d0;
395	            int d1;
396	
397	            if (lrk == 0) {
398	                // Scalar shape -> vector
399	                new_rank = 1;
400	                d0 = arr_get(lv, 0);
401	                d1 = 0;
402	                if (d0 < 0) { eval_err = 1; return -1; }
403	            } else if (lrk == 1) {
404	                int lsz = arr_size(lv);
405	                if (lsz == 1) {
406	                    new_rank = 1;
407	                    d0 = arr_get(lv, 0);
408	                    d1 = 0;
409	                    if (d0 < 0) { eval_err = 1; return -1; }
410	                } else if (lsz == 2) {
411	                    new_rank = 2;
412	                    d0 = arr_get(lv, 0);
413	                    d1 = arr_get(lv, 1);
414	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
415	                } else {
416	                    // Only rank 1 and 2 supported
417	                    eval_err = 4;
418	                    return -1;
419	                }
420	            } else {
421	                eval_err = 4;
422	                return -1;
423	            }
424	
425	            int r = arr_new(new_rank, d0, d1);
426	            if (r < 0) { eval_err = 5; return -1; }
427	
428	            int total = arr_size(r);
429	            int src_sz = arr_size(rv);
430	            if (src_sz == 0) { eval_err = 3; return -1; }
431	
432	            int i = 0;
433	            while (i < total) {
434	                arr_set(r, i, arr_get(rv, i % src_sz));
435	                i++;
436	            }
437	            return r;
438	        }
439	
440	        if (res_id == RES_TAKE) {
441	            // N take A: take first N elements/rows (negative N = from end)
442	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
443	            int count = arr_get(lv, 0);
444	            int rrk = arr_rank(rv);
445	
446	            if (rrk <= 1) {
447	                int sz = arr_size(rv);
448	                int abs_n = count;
449	                if (abs_n < 0) abs_n = 0 - abs_n;
450	                if (abs_n > sz) { eval_err = 3; return -1; }
451	
452	                int r = arr_vector(abs_n);
453	                if (r < 0) { eval_err = 5; return -1; }
454	                int start = 0;
455	                if (count < 0) start = sz - abs_n;
456	                int i = 0;
457	                while (i < abs_n) {
458	                    arr_set(r, i, arr_get(rv, start + i));
459	                    i++;
460	                }
461	                return r;
462	            }
463	
464	            if (rrk == 2) {
465	                int rows = arr_dim0(rv);
466	                int cols = arr_dim1(rv);
467	                int abs_n = count;
468	                if (abs_n < 0) abs_n = 0 - abs_n;
469	                if (abs_n > rows) { eval_err = 3; return -1; }
470	
471	                int r = arr_new(2, abs_n, cols);
472	                if (r < 0) { eval_err = 5; return -1; }
473	                int start_row = 0;
474	                if (count < 0) start_row = rows - abs_n;
475	                int total = abs_n * cols;
476	                int i = 0;
477	                while (i < total) {
478	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
479	                    i++;
480	                }
481	                return r;
482	            }
483	
484	            eval_err = 4;
485	            return -1;
486	        }
487	
488	        if (res_id == RES_DROP) {
489	            // N drop A: drop first N elements/rows (negative N = from end)
490	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
491	            int count = arr_get(lv, 0);
492	            int rrk = arr_rank(rv);
493	
494	            if (rrk <= 1) {
495	                int sz = arr_size(rv);
496	                int abs_n = count;
497	                if (abs_n < 0) abs_n = 0 - abs_n;
498	                if (abs_n > sz) abs_n = sz;
499	
500	                int new_sz = sz - abs_n;
501	                int r = arr_vector(new_sz);
502	                if (r < 0) { eval_err = 5; return -1; }
503	                int start = abs_n;
504	                if (count < 0) start = 0;
505	                int i = 0;
506	                while (i < new_sz) {
507	                    arr_set(r, i, arr_get(rv, start + i));
508	                    i++;
509	                }
510	                return r;
511	            }
512	
513	            if (rrk == 2) {
514	                int rows = arr_dim0(rv);
515	                int cols = arr_dim1(rv);
516	                int abs_n = count;
517	                if (abs_n < 0) abs_n = 0 - abs_n;
518	                if (abs_n > rows) abs_n = rows;
519	
520	                int new_rows = rows - abs_n;
521	                int r = arr_new(2, new_rows, cols);
522	                if (r < 0) { eval_err = 5; return -1; }
523	                int start_row = abs_n;
524	                if (count < 0) start_row = 0;
525	                int total = new_rows * cols;
526	                int i = 0;
527	                while (i < total) {
528	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
529	                    i++;
530	                }
531	                return r;
532	            }
533	
534	            eval_err = 4;
535	            return -1;
